"""
Coherence layer 1 — NLI-style scoring for claim pairs (DeBERTa cross-encoder).
"""

from __future__ import annotations

from dataclasses import dataclass
from typing import Any, Optional

import numpy as np

from noosphere.models import Claim, CoherenceVerdict, SixLayerScore
from noosphere.observability import get_logger

logger = get_logger(__name__)


@dataclass
class NLIProbabilities:
    entailment: float
    neutral: float
    contradiction: float


def _softmax(logits: np.ndarray) -> np.ndarray:
    x = logits - np.max(logits)
    e = np.exp(x)
    return e / e.sum()


class NLIScorer:
    """
    Pair classifier using a cross-encoder (DeBERTa-v3 NLI head family).
    """

    def __init__(self, model_name: str = "cross-encoder/nli-deberta-v3-base") -> None:
        self.model_name = model_name
        self._model: Any = None
        self._nli_idx: Optional[tuple[int, int, int]] = None  # entailment, neutral, contradiction

    def _model_obj(self):
        if self._model is None:
            from sentence_transformers import CrossEncoder

            self._model = CrossEncoder(self.model_name)
            cfg = self._model.model.config
            id2label = getattr(cfg, "id2label", None) or {}
            ent = neu = con = None
            for k, v in id2label.items():
                i = int(k)
                name = str(v).lower()
                if "entail" in name:
                    ent = i
                elif "neutral" in name:
                    neu = i
                elif "contradict" in name:
                    con = i
            if ent is not None and neu is not None and con is not None:
                self._nli_idx = (ent, neu, con)
            else:
                # cross-encoder/nli-deberta-v3-base: 0=c, 1=e, 2=n
                self._nli_idx = (1, 2, 0)
        return self._model

    def _map_nli_probs(self, logits3: np.ndarray) -> tuple[float, float, float]:
        probs = _softmax(np.asarray(logits3, dtype=float).reshape(-1)[:3])
        ei, ni, ci = self._nli_idx or (1, 2, 0)
        return float(probs[ei]), float(probs[ni]), float(probs[ci])

    def score_pair(self, premise: str, hypothesis: str) -> tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]:
        logits = self._model_obj().predict([(premise, hypothesis)], show_progress_bar=False)
        arr = np.asarray(logits, dtype=float).reshape(-1)
        if arr.size >= 3:
            ent, neu, con = self._map_nli_probs(arr[:3])
        else:
            ent, neu, con = 0.33, 0.34, 0.33
        nli = NLIProbabilities(entailment=ent, neutral=neu, contradiction=con)
        s1 = float(1.0 - nli.contradiction)
        partial = SixLayerScore(s1_consistency=s1)
        if nli.contradiction >= 0.55 and nli.contradiction > nli.entailment:
            verdict = CoherenceVerdict.CONTRADICT
        elif nli.entailment >= 0.55:
            verdict = CoherenceVerdict.COHERE
        else:
            verdict = CoherenceVerdict.UNRESOLVED
        return nli, partial, verdict

    def score_claim_pair(self, a: Claim, b: Claim) -> tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]:
        return self.score_pair(a.text, b.text)

    def score_pairs_batch(
        self, pairs: list[tuple[str, str]]
    ) -> list[tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]]:
        logits = self._model_obj().predict(pairs, show_progress_bar=False)
        out: list[tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]] = []
        mat = np.asarray(logits, dtype=float)
        if mat.ndim == 1:
            mat = mat.reshape(1, -1)
        for row in mat:
            if row.size >= 3:
                ent, neu, con = self._map_nli_probs(row[:3])
            else:
                ent, neu, con = 0.33, 0.34, 0.33
            nli = NLIProbabilities(entailment=ent, neutral=neu, contradiction=con)
            s1 = float(1.0 - nli.contradiction)
            partial = SixLayerScore(s1_consistency=s1)
            if nli.contradiction >= 0.55 and nli.contradiction > nli.entailment:
                v = CoherenceVerdict.CONTRADICT
            elif nli.entailment >= 0.55:
                v = CoherenceVerdict.COHERE
            else:
                v = CoherenceVerdict.UNRESOLVED
            out.append((nli, partial, v))
        return out


class StubNLIScorer:
    """Test double with no transformer load."""

    def __init__(
        self,
        *,
        verdict: CoherenceVerdict = CoherenceVerdict.UNRESOLVED,
        partial: Optional[SixLayerScore] = None,
    ) -> None:
        self._verdict = verdict
        self._partial = partial or SixLayerScore(s1_consistency=0.5)

    def score_pair(
        self, premise: str, hypothesis: str
    ) -> tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]:
        return (
            NLIProbabilities(0.34, 0.33, 0.33),
            self._partial,
            self._verdict,
        )

    def score_claim_pair(self, a: Claim, b: Claim) -> tuple[NLIProbabilities, SixLayerScore, CoherenceVerdict]:
        return self.score_pair(a.text, b.text)

"""
Coherence layer 4 — embedding geometry (Hoyer sparsity + cosine vs reference corpus).
"""

from __future__ import annotations

import json
from dataclasses import dataclass
from pathlib import Path
from typing import Optional

import numpy as np

from noosphere.models import Claim, CoherenceVerdict
from noosphere.observability import get_logger

logger = get_logger(__name__)


def hoyer_sparsity(x: np.ndarray) -> float:
    n = len(x)
    if n <= 1:
        return 0.0
    l1 = np.sum(np.abs(x))
    l2 = np.sqrt(np.sum(x**2))
    if l2 == 0:
        return 0.0
    return (np.sqrt(n) - l1 / l2) / (np.sqrt(n) - 1)


@dataclass
class GeometryLayerResult:
    score: float
    verdict: CoherenceVerdict
    hoyer_residual: float
    mean_cosine_reference: float


def _default_calibration() -> tuple[float, float]:
    """(hoyer_threshold, cosine_threshold) from repo experiments if present."""
    root = Path(__file__).resolve().parents[3]
    cand = root / "ideologicalOntology" / "Contradiction_Geometry" / "results" / "refined_detector_results.json"
    if cand.is_file():
        try:
            data = json.loads(cand.read_text(encoding="utf-8"))
            # Heuristic: use summary fields if present
            if isinstance(data, dict) and "threshold" in data:
                t = float(data["threshold"])
                return t, 0.35
        except (json.JSONDecodeError, OSError, TypeError, ValueError):
            pass
    return 0.35, 0.35


def score_claim_geometry(
    emb_a: np.ndarray,
    emb_b: np.ndarray,
    reference_matrix: Optional[np.ndarray] = None,
) -> GeometryLayerResult:
    ref = reference_matrix
    if ref is None or ref.size == 0:
        ref = np.stack([emb_a, emb_b], axis=0)
    diff = emb_a - emb_b
    h = float(hoyer_sparsity(diff))
    # cosine angles vs reference mean direction
    ref_mean = ref.mean(axis=0)
    ref_mean = ref_mean / (np.linalg.norm(ref_mean) + 1e-9)
    ca = float(np.dot(emb_a / (np.linalg.norm(emb_a) + 1e-9), ref_mean))
    cb = float(np.dot(emb_b / (np.linalg.norm(emb_b) + 1e-9), ref_mean))
    mean_c = (ca + cb) / 2.0
    th_h, th_c = _default_calibration()
    score = float(np.clip(h / (th_h + 1e-6), 0.0, 1.0))
    if h >= th_h and mean_c < th_c:
        verdict = CoherenceVerdict.CONTRADICT
    elif h < th_h * 0.5:
        verdict = CoherenceVerdict.COHERE
    else:
        verdict = CoherenceVerdict.UNRESOLVED
    return GeometryLayerResult(
        score=score,
        verdict=verdict,
        hoyer_residual=h,
        mean_cosine_reference=mean_c,
    )


def geometry_from_claims(a: Claim, b: Claim) -> GeometryLayerResult:
    if not a.embedding or not b.embedding:
        return GeometryLayerResult(
            0.5, CoherenceVerdict.UNRESOLVED, 0.0, 0.0
        )
    ea = np.asarray(a.embedding, dtype=float)
    eb = np.asarray(b.embedding, dtype=float)
    return score_claim_geometry(ea, eb, None)

from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")


def register_method(
    *,
    name: str,
    version: str,
    method_type: MethodType,
    input_schema: Any,
    output_schema: Any,
    description: str,
    rationale: str,
    preconditions: list[str] | tuple[str, ...] = (),
    postconditions: list[str] | tuple[str, ...] = (),
    dependencies: list[tuple[str, str]] | tuple[tuple[str, str], ...] = (),
    owner: str,
    status: str = "active",
    nondeterministic: bool = False,
    emits_edges: list[CascadeEdgeRelation] | tuple[CascadeEdgeRelation, ...] = (),
) -> Callable:
    def decorator(fn: Callable) -> Callable:
        if isinstance(input_schema, type) and issubclass(input_schema, BaseModel):
            in_schema_dict = input_schema.model_json_schema()
        elif isinstance(input_schema, dict):
            in_schema_dict = input_schema
        else:
            in_schema_dict = {}

        if isinstance(output_schema, type) and issubclass(output_schema, BaseModel):
            out_schema_dict = output_schema.model_json_schema()
        elif isinstance(output_schema, dict):
            out_schema_dict = output_schema
        else:
            out_schema_dict = {}

        impl = MethodImplRef(
            module=fn.__module__,
            fn_name=fn.__qualname__,
            git_sha=_current_git_sha(),
            image_digest=None,
        )

        spec_for_hash = {
            "name": name,
            "version": version,
            "method_type": method_type.value,
            "input_schema": in_schema_dict,
            "output_schema": out_schema_dict,
            "description": description,
            "rationale": rationale,
            "preconditions": list(preconditions),
            "postconditions": list(postconditions),
            "dependencies": [list(d) for d in dependencies],
            "implementation": impl.model_dump(mode="json"),
            "owner": owner,
            "status": status,
            "nondeterministic": nondeterministic,
        }

        method_id = hashlib.sha256(
            _canonical_json(spec_for_hash).encode()
        ).hexdigest()[:32]

        spec = Method(
            method_id=method_id,
            name=name,
            version=version,
            method_type=method_type,
            input_schema=in_schema_dict,
            output_schema=out_schema_dict,
            description=description,
            rationale=rationale,
            preconditions=list(preconditions),
            postconditions=list(postconditions),
            dependencies=list(dependencies),
            implementation=impl,
            owner=owner,
            status=status,
            nondeterministic=nondeterministic,
            created_at=_utcnow(),
        )

        @wraps(fn)
        def wrapped(input_data: Any) -> Any:
            validated_input = _validate_against_schema(input_schema, input_data)
            input_hash = hashlib.sha256(
                _canonical_json(validated_input).encode()
            ).hexdigest()

            inv = MethodInvocation(
                id=str(uuid4()),
                method_id=spec.method_id,
                input_hash=input_hash,
                output_hash="",
                started_at=_utcnow(),
                ended_at=None,
                succeeded=False,
                error_kind=None,
                correlation_id=_current_correlation_id(),
                tenant_id=_current_tenant_id(),
            )

            try:
                for _hook_name, hook in _PRE_HOOKS:
                    hook(spec, inv, validated_input)
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

            try:
                result = fn(validated_input)
                _validate_against_schema(output_schema, result)
                output_hash = hashlib.sha256(
                    _canonical_json(result).encode()
                ).hexdigest()
                inv = inv.model_copy(
                    update={
                        "ended_at": _utcnow(),
                        "succeeded": True,
                        "output_hash": output_hash,
                    }
                )

                for hook_name, hook in _POST_HOOKS:
                    try:
                        hook(spec, inv, validated_input, result)
                    except Exception:
                        logger.exception("Post-hook %s raised", hook_name)

                store = _get_store()
                if store is not None:
                    try:
                        store.insert_method_invocation(inv)
                    except Exception:
                        logger.exception("Failed to persist invocation")

                return result
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

        wrapped.__method_spec__ = spec  # type: ignore[attr-defined]

        REGISTRY.register(spec, wrapped)

        if emits_edges:
            REGISTRY.set_emits_edges(method_id, list(emits_edges))

        store = _get_store()
        if store is not None:
            try:
                store.insert_method(spec)
            except Exception:
                logger.exception("Failed to persist method spec")

        return wrapped

    return decorator

from __future__ import annotations

from typing import Callable

from noosphere.models import CascadeEdgeRelation, Method


class MethodCollisionError(Exception):
    pass


class MethodNotFoundError(Exception):
    pass


def _parse_semver(version: str) -> tuple[int, ...]:
    parts: list[int] = []
    for p in version.split("."):
        try:
            parts.append(int(p))
        except ValueError:
            parts.append(0)
    return tuple(parts)


class MethodRegistry:
    def __init__(self) -> None:
        self._specs: dict[tuple[str, str], Method] = {}
        self._fns: dict[tuple[str, str], Callable] = {}
        self._emits_edges: dict[str, list[CascadeEdgeRelation]] = {}

    def register(self, spec: Method, fn: Callable) -> None:
        key = (spec.name, spec.version)
        if key in self._specs:
            raise MethodCollisionError(
                f"Method {spec.name} v{spec.version} already registered"
            )
        self._specs[key] = spec
        self._fns[key] = fn

    def set_emits_edges(
        self, method_id: str, edges: list[CascadeEdgeRelation]
    ) -> None:
        self._emits_edges[method_id] = list(edges)

    def get_emits_edges(self, method_id: str) -> list[CascadeEdgeRelation]:
        return self._emits_edges.get(method_id, [])

    def get(
        self,
        name: str,
        version: str = "latest",
        include_retired: bool = False,
    ) -> tuple[Method, Callable]:
        if version != "latest":
            key = (name, version)
            if key not in self._specs:
                raise MethodNotFoundError(
                    f"Method {name} v{version} not found"
                )
            spec = self._specs[key]
            if spec.status == "retired" and not include_retired:
                raise MethodNotFoundError(
                    f"Method {name} v{version} is retired"
                )
            return spec, self._fns[key]

        candidates: list[tuple[str, Method]] = []
        for (n, v), spec in self._specs.items():
            if n != name:
                continue
            if spec.status == "retired" and not include_retired:
                continue
            candidates.append((v, spec))

        if not candidates:
            raise MethodNotFoundError(f"No active method found for {name}")

        candidates.sort(key=lambda x: _parse_semver(x[0]), reverse=True)
        best_version = candidates[0][0]
        return self._specs[(name, best_version)], self._fns[(name, best_version)]

    def list(self, status_filter: str | None = None) -> list[Method]:
        specs = list(self._specs.values())
        if status_filter is not None:
            specs = [s for s in specs if s.status == status_filter]
        return specs


REGISTRY = MethodRegistry()

from __future__ import annotations

from typing import Any, Callable

from noosphere.models import Method, MethodInvocation

PreHook = Callable[[Method, MethodInvocation, Any], None]
PostHook = Callable[[Method, MethodInvocation, Any, Any], None]
FailureHook = Callable[[Method, MethodInvocation, Any, BaseException], None]

_PRE_HOOKS: list[tuple[str, PreHook]] = []
_POST_HOOKS: list[tuple[str, PostHook]] = []
_FAILURE_HOOKS: list[tuple[str, FailureHook]] = []


def _replace_or_append(
    lst: list[tuple[str, Callable]], name: str, hook: Callable
) -> None:
    for i, (n, _) in enumerate(lst):
        if n == name:
            lst[i] = (name, hook)
            return
    lst.append((name, hook))


def register_pre_hook(name: str, hook: PreHook) -> None:
    _replace_or_append(_PRE_HOOKS, name, hook)


def register_post_hook(name: str, hook: PostHook) -> None:
    _replace_or_append(_POST_HOOKS, name, hook)


def register_failure_hook(name: str, hook: FailureHook) -> None:
    _replace_or_append(_FAILURE_HOOKS, name, hook)


def unregister_hook(name: str) -> None:
    for lst in (_PRE_HOOKS, _POST_HOOKS, _FAILURE_HOOKS):
        lst[:] = [(n, h) for n, h in lst if n != name]

